#include "pngw3_hlms.h"

#define DEFFUNC(L, M) \
INT evaluate_h##L##M(REAL8 eta, REAL8 l, DynParamsCache *dc, PNEllipticEvaluator *pe,\
    REAL8 *hr, REAL8 *hi, REAL8 eps)\
{\
    if(pe->is_zeroe) {\
        COMPLEX16 h = cexp(I*l*(-M))*calculate_h##L##M##FourierMode_zeroe(eta, dc);\
        *hr = creal(h);\
        *hi = cimag(h);\
        return X_SUCCESS;\
    }\
    REAL8 hrPos=0.0, hrNeg=0.0, hiPos=0.0, hiNeg=0.0;\
    size_t min_iter = 5;\
    size_t cons_iter = 3, ici = 0;\
    REAL8 cum;\
    cum = 0.0;\
    for (int pp = 1;  ; pp++)\
    {\
        COMPLEX16 coeff = calculate_h##L##M##FourierModep(pp+(M), eta, dc, pe) ;\
        COMPLEX16 term = coeff * cexp(l*I*pp);\
        REAL8 abscoeff = cabs(coeff);\
        hrPos += creal(term);\
        hiPos += cimag(term);\
        cum += abscoeff;\
        if (pp > min_iter && abscoeff < eps*cum) {\
            if (ici >cons_iter)\
                break;\
            else\
                ici++;\
        } else \
            ici = 0;\
    }\
    cum = 0.0;\
    for (int pp = 1;  ; pp++)\
    {\
        COMPLEX16 coeff = calculate_h##L##M##FourierModep(-pp+(M), eta, dc, pe) ;\
        COMPLEX16 term = coeff * cexp(-l*I*pp);\
        REAL8 abscoeff = cabs(coeff);\
        hrNeg += creal(term);\
        hiNeg += cimag(term);\
        cum += abscoeff;\
        if (pp > min_iter && abscoeff < eps*cum) {\
            if (ici >cons_iter)\
                break;\
            else\
                ici++;\
        } else \
            ici = 0;\
    }\
    *hr = hrPos + hrNeg;\
    *hi = hiPos + hiNeg;\
    return X_SUCCESS;\
}

#define SQ1O66 0.123091490979332732734240660125243035583397032
