COMPLEX16 calculate_h52FourierMode_zeroe(REAL8 eta, DynParamsCache *dc)
{
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

#define CPREF 0.1348399724926484172492981352872856920178164421654091199769567866
    REAL8 PN4 = CPREF*(4*(1 - 5*eta + 5*eta2))/27.;
    REAL8 PN6 = CPREF*(2*(-3911 + 21553*eta - 28910*eta2 + 8085*eta3))/12285.;

    return v2*v2*(PN4 + v2*PN6);
#undef CPREF
}

